import React, { useEffect, useMemo, useState } from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

function RecipesPage() {
  let [recipes, setRecipes] = useState([]);
  let [search, setSearch] = useState("");
  let [selectedCategory, setSelectedCategory] = useState("");
  let [selectedDifficulty, setSelectedDifficulty] = useState("");
  let [selectedDiet, setSelectedDiet] = useState("");
  let [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("http://localhost:5000/przepisy")
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setRecipes(data);
        } else {
          setRecipes([]);
        }
        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setRecipes([]);
        setLoading(false);
      });
  }, []);

  let categories = useMemo(() => {
    let values = recipes
      .map((recipe) => recipe.kategoria_id)
      .filter((value) => value !== null && value !== undefined);

    return [...new Set(values)];
  }, [recipes]);

  let difficulties = useMemo(() => {
    let values = recipes
      .map((recipe) => recipe.poziom_trudnosci)
      .filter((value) => value);

    return [...new Set(values)];
  }, [recipes]);

  let diets = useMemo(() => {
    let values = recipes
      .map((recipe) => recipe.dieta)
      .filter((value) => value);

    return [...new Set(values)];
  }, [recipes]);

  let filteredRecipes = recipes.filter((recipe) => {
    let matchSearch =
      !search ||
      recipe.tytul?.toLowerCase().includes(search.toLowerCase());

    let matchCategory =
      !selectedCategory ||
      String(recipe.kategoria_id) === String(selectedCategory);

    let matchDifficulty =
      !selectedDifficulty ||
      recipe.poziom_trudnosci === selectedDifficulty;

    let matchDiet =
      !selectedDiet ||
      recipe.dieta === selectedDiet;

    return matchSearch && matchCategory && matchDifficulty && matchDiet;
  });

  return (
    <div className="app">
      <Navbar />

      <section className="recipes-page">
        <div className="container">
          <div className="recipes-page-header">
            <h1>Przepisy</h1>
            <p>Przeglądaj przepisy, wyszukuj po nazwie i filtruj wyniki.</p>
          </div>

          <div className="recipes-layout">
            <aside className="filters-sidebar">
              <h3>Filtry</h3>

              <div className="filter-group">
                <label>Wyszukaj nazwę</label>
                <input
                  type="text"
                  placeholder="Np. makaron"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
              </div>

              <div className="filter-group">
                <label>Kategoria</label>
                <select
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {categories.map((category) => (
                    <option key={category} value={category}>
                      Kategoria {category}
                    </option>
                  ))}
                </select>
              </div>

              <div className="filter-group">
                <label>Poziom trudności</label>
                <select
                  value={selectedDifficulty}
                  onChange={(e) => setSelectedDifficulty(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {difficulties.map((difficulty) => (
                    <option key={difficulty} value={difficulty}>
                      {difficulty}
                    </option>
                  ))}
                </select>
              </div>

              <div className="filter-group">
                <label>Dieta</label>
                <select
                  value={selectedDiet}
                  onChange={(e) => setSelectedDiet(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {diets.map((diet) => (
                    <option key={diet} value={diet}>
                      {diet}
                    </option>
                  ))}
                </select>
              </div>

              <button
                className="clear-filters-button"
                onClick={() => {
                  setSearch("");
                  setSelectedCategory("");
                  setSelectedDifficulty("");
                  setSelectedDiet("");
                }}
              >
                Wyczyść filtry
              </button>
            </aside>

            <div className="recipes-content">
              {loading ? (
                <p>Ładowanie przepisów...</p>
              ) : filteredRecipes.length === 0 ? (
                <p>Brak przepisów pasujących do filtrów.</p>
              ) : (
                <div className="recipes-list-grid">
                  {filteredRecipes.map((recipe) => (
                    <div className="recipe-list-card" key={recipe.id}>
                      <div className="recipe-list-card-body">
                        <h3>{recipe.tytul}</h3>

                        <div className="recipe-list-meta">
                          <span>Czas: {recipe.czas_przygotowania_min} min</span>
                          <span>Trudność: {recipe.poziom_trudnosci || "Brak"}</span>
                        </div>

                        <div className="recipe-list-meta">
                          <span>Dieta: {recipe.dieta || "Brak"}</span>
                          <span>Kategoria: {recipe.kategoria_id || "Brak"}</span>
                        </div>

                        <p className="recipe-list-description">
                          {recipe.opis || "Brak opisu przepisu."}
                        </p>

                        <button className="secondary-button">
                          Zobacz szczegóły
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
}

export default RecipesPage;
